function updateUserProfile(user, updates) {
  // Создаём новый объект, не мутируя исходный
  // undefined-поля в updates перезапишут существующие — фильтруем
  const cleanUpdates = Object.fromEntries(
    Object.entries(updates).filter(([, v]) => v !== undefined)
  );
  return { ...user, ...cleanUpdates };
}

// Теперь user не изменяется
const updated = updateUserProfile(user, { name: 'Мария', email: 'maria@example.com' });
console.log(user === updated); // false — разные объекты
console.log(user.name);       // 'Иван' — не изменился
console.log(updated.name);    // 'Мария'
console.log(updated.age);     // 25 — сохранено из оригинала
